package lista01;

import java.util.Scanner;

public class Exercicio05 {

	public static void main(String[] args) {
		// TODO Auto-generated method stub
		
		Scanner teclado = new Scanner(System.in);
		
		System.out.print("Usuário digite o número que queira saber: ");
		int numero1 = teclado.nextInt ();
		
		System.out.println("Seu antecessor é igual a " + (numero1 - 1) + " e seu sucessor é igual a " + (numero1 + 1) + ".");
		
		teclado.close();
		
		/* CRIE UM ALGORITMO QUE LEIA UM VALOR NUMÉRICO INTEIRO E APRESENTE COMO RESULTADO O SEU
		ANTECESSOR E O SEU SUCESSOR.
		 * 
		 */




	}

}
